package com.wjx871.population.floating;import java.time.*;import org.springframework.stereotype.Component;
@Component public class ResidencePermitDatePolicy {private final ResidencePermitProperties p;private final Clock clock;public ResidencePermitDatePolicy(ResidencePermitProperties p,Clock c){this.p=p;this.clock=c;}public LocalDate today(){return LocalDate.now(clock);}public LocalDate eligibleFrom(LocalDate arrival){return arrival.plusDays(p.getMinResidenceDays());}public LocalDate firstValidUntil(LocalDate from){return from.plusDays(p.getValidityDays());}public LocalDate endorsedUntil(LocalDate old){LocalDate base=old.isAfter(today())?old:today();return base.plusDays(p.getValidityDays());}public boolean endorsementOpen(LocalDate until){return !today().isBefore(until.minusDays(p.getEndorsementEarlyDays()));}public LocalDate warningUntil(){return today().plusDays(p.getExpiryWarningDays());}}
